import org.junit.BeforeClass;
import org.junit.Test;
import java.io.File;
import java.io.FileOutputStream;
import java.io.IOException;
import java.util.Properties;
import static org.junit.Assert.*;

public class EnvironmentTest {

    private static final String TEST_FILE_NAME = "application.properties";
    private static final String APP_VERSION_KEY = "app.version";
    private static final String APP_VERSION_VALUE = "0.0.2";
    private static final String APP_LANG_KEY = "app.lang";
    private static final String APP_LANG_VALUE = "cn";

    @BeforeClass
    public static void setUp() throws IOException {
        // Create properties file in current folder (precondition 1)
        Properties props = new Properties();
        props.setProperty(APP_VERSION_KEY, APP_VERSION_VALUE);
        props.setProperty(APP_LANG_KEY, APP_LANG_VALUE);
        File file = new File(TEST_FILE_NAME);
        try (FileOutputStream fos = new FileOutputStream(file)) {
            props.store(fos, "Test properties");
        }

        // Ensure the same file is in classpath (precondition 2)
        // This is typically done by placing the file in src/test/resources
        // For this test, we rely on the file being in the current directory,
        // which is often included in the classpath during tests.
    }

    @Test
    public void testOfStringLocationWithFileAndClasspath() {
        // Test loading from file location (using file: prefix)
        Environment envFromFile = Environment.of("file:" + TEST_FILE_NAME);
        assertNotNull("Environment from file should not be null", envFromFile);
        assertEquals("File: app.version should match", APP_VERSION_VALUE, envFromFile.getOrNull(APP_VERSION_KEY));
        assertEquals("File: app.lang should match", APP_LANG_VALUE, envFromFile.getOrNull(APP_LANG_KEY));

        // Test loading from classpath resource (without prefix, falls back to loadClasspath)
        Environment envFromClasspath = Environment.of(TEST_FILE_NAME);
        assertNotNull("Environment from classpath should not be null", envFromClasspath);
        assertEquals("Classpath: app.version should match", APP_VERSION_VALUE, envFromClasspath.getOrNull(APP_VERSION_KEY));
        assertEquals("Classpath: app.lang should match", APP_LANG_VALUE, envFromClasspath.getOrNull(APP_LANG_KEY));

        // Additional check: ensure both environments are not empty and have keys
        assertFalse("File environment should not be empty", envFromFile.isEmpty());
        assertFalse("Classpath environment should not be empty", envFromClasspath.isEmpty());
        assertTrue("File environment should have app.version key", envFromFile.hasKey(APP_VERSION_KEY));
        assertTrue("Classpath environment should have app.lang key", envFromClasspath.hasKey(APP_LANG_KEY));
    }
}

